import React, { useRef, useEffect } from 'react';
import { View, Alert, Platform, PermissionsAndroid } from 'react-native';
import { WebView } from 'react-native-webview';
import { launchCamera } from 'react-native-image-picker';
import Geolocation from '@react-native-community/geolocation';

const ALLOWED_ORIGINS = [
  'https://yourdomain.com',
  'https://www.yourdomain.com'
];

const ALLOWED_ACTIONS = ['camera', 'location'];

const SecureWebViewComponent = () => {
  const webViewRef = useRef(null);

  const validateOrigin = (url) => {
    try {
      const urlObj = new URL(url);
      return ALLOWED_ORIGINS.some(origin => {
        const allowedOrigin = new URL(origin);
        return urlObj.origin === allowedOrigin.origin;
      });
    } catch (e) {
      return false;
    }
  };

  const validateMessage = (message) => {
    if (!message || typeof message !== 'object') {
      return false;
    }

    const { action, requestId } = message;

    if (!action || typeof action !== 'string') {
      return false;
    }

    if (!ALLOWED_ACTIONS.includes(action)) {
      return false;
    }

    if (!requestId || typeof requestId !== 'string') {
      return false;
    }

    return true;
  };

  const requestCameraPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.CAMERA,
          {
            title: 'Camera Permission',
            message: 'App needs access to your camera',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        return false;
      }
    }
    return true;
  };

  const requestLocationPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
          {
            title: 'Location Permission',
            message: 'App needs access to your location',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        return false;
      }
    }
    return true;
  };

  const handleCamera = async (requestId) => {
    const hasPermission = await requestCameraPermission();
    
    if (!hasPermission) {
      sendMessageToWeb({
        requestId,
        success: false,
        error: 'Camera permission denied'
      });
      return;
    }

    launchCamera(
      {
        mediaType: 'photo',
        quality: 0.8,
        maxWidth: 1920,
        maxHeight: 1080,
      },
      (response) => {
        if (response.didCancel) {
          sendMessageToWeb({
            requestId,
            success: false,
            error: 'User cancelled'
          });
        } else if (response.errorCode) {
          sendMessageToWeb({
            requestId,
            success: false,
            error: response.errorMessage
          });
        } else if (response.assets && response.assets[0]) {
          sendMessageToWeb({
            requestId,
            success: true,
            data: {
              uri: response.assets[0].uri,
              type: response.assets[0].type,
              fileName: response.assets[0].fileName
            }
          });
        }
      }
    );
  };

  const handleLocation = async (requestId) => {
    const hasPermission = await requestLocationPermission();
    
    if (!hasPermission) {
      sendMessageToWeb({
        requestId,
        success: false,
        error: 'Location permission denied'
      });
      return;
    }

    Geolocation.getCurrentPosition(
      (position) => {
        sendMessageToWeb({
          requestId,
          success: true,
          data: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
            accuracy: position.coords.accuracy
          }
        });
      },
      (error) => {
        sendMessageToWeb({
          requestId,
          success: false,
          error: error.message
        });
      },
      {
        enableHighAccuracy: true,
        timeout: 15000,
        maximumAge: 10000
      }
    );
  };

  const sendMessageToWeb = (message) => {
    if (webViewRef.current) {
      webViewRef.current.postMessage(JSON.stringify(message));
    }
  };

  const handleWebViewMessage = async (event) => {
    const currentUrl = event.nativeEvent.url;

    if (!validateOrigin(currentUrl)) {
      console.warn('Message from unauthorized origin:', currentUrl);
      return;
    }

    let message;
    try {
      message = JSON.parse(event.nativeEvent.data);
    } catch (e) {
      console.warn('Invalid message format');
      return;
    }

    if (!validateMessage(message)) {
      console.warn('Invalid message structure or action');
      sendMessageToWeb({
        requestId: message?.requestId || 'unknown',
        success: false,
        error: 'Invalid request'
      });
      return;
    }

    const { action, requestId } = message;

    switch (action) {
      case 'camera':
        await handleCamera(requestId);
        break;
      case 'location':
        await handleLocation(requestId);
        break;
      default:
        sendMessageToWeb({
          requestId,
          success: false,
          error: 'Unknown action'
        });
    }
  };

  const handleNavigationStateChange = (navState) => {
    if (!validateOrigin(navState.url)) {
      console.warn('Navigation to unauthorized origin blocked:', navState.url);
      webViewRef.current?.stopLoading();
      Alert.alert('Navigation Blocked', 'Cannot navigate to unauthorized domain');
      return false;
    }
  };

  const handleShouldStartLoadWithRequest = (request) => {
    return validateOrigin(request.url);
  };

  return (
    <View style={{ flex: 1 }}>
      <WebView
        ref={webViewRef}
        source={{ uri: 'https://yourdomain.com' }}
        javaScriptEnabled={true}
        domStorageEnabled={false}
        allowFileAccess={false}
        allowFileAccessFromFileURLs={false}
        allowUniversalAccessFromFileURLs={false}
        geolocationEnabled={false}
        saveFormDataDisabled={true}
        thirdPartyCookiesEnabled={false}
        mixedContentMode="never"
        onMessage={handleWebViewMessage}
        onNavigationStateChange={handleNavigationStateChange}
        onShouldStartLoadWithRequest={handleShouldStartLoadWithRequest}
        originWhitelist={ALLOWED_ORIGINS}
        allowsInlineMediaPlayback={false}
        mediaPlaybackRequiresUserAction={true}
        startInLoadingState={true}
        scalesPageToFit={true}
      />
    </View>
  );
};

export default SecureWebViewComponent;